import threading

class CardMonitor:
    def __init__(self):
        self.running = False
        self._thread = None
        self._last_uid = None

    def start(self):
        self.running = True
        self._thread = threading.Thread(target=self._poll)
        self._thread.start()

    def _poll(self):
        while self.running:
            try:
                uid = self._read_card()
                if uid != self._last_uid:
                    self._last_uid = uid
                    self.on_card_detected(uid)
            except Exception:
                pass  # ignore errors

    def stop(self):
        self.running = False
